+fn build_dependency_indexes(
+    ctx: &AppContext,
+) -> Result<(
+    HashMap<String, SkillRecord>,
+    HashMap<String, Vec<String>>,
+    HashMap<String, CachedMeta>,
+)> {
+    let mut all_skills = Vec::new();
